                  </button>
                  <input 
                    type="file" 
                    ref={mediaInputRef}
                    className="hidden"
                    multiple
                    accept="image/*,video/*"
                    onChange={handleMediaUpload}
                  />
                </div>

                <div className="grid grid-cols-4 gap-2 max-h-[200px] overflow-y-auto p-1">
                  {currentAlbum?.media?.map((item) => (
                    <div key={item.id} className="relative aspect-square rounded-lg bg-gray-100 overflow-hidden group/media">
                      {item.type === 'image' ? (
                        <Image src={item.url} fill sizes="100px" alt={currentAlbum.title ? `${currentAlbum.title} media` : "Gallery photo"} className="object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center bg-gray-200">
                          <Camera size={20} className="text-gray-400" />
                          <div className="absolute top-1 left-1 bg-black/50 rounded-md px-1 py-0.5">
                            <span className="text-[8px] text-white font-bold uppercase tracking-widest">Video</span>
                          </div>
                        </div>
                      )}
                      <button 
                        onClick={() => removeMediaItem(item.id)}
                        className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-md opacity-0 group-hover/media:opacity-100 transition-opacity"
                      >
                        <X size={10} />
                      </button>
                    </div>
                  ))}
                  {currentAlbum?.media?.length === 0 && (
                    <div className="col-span-4 py-8 text-center border border-dashed border-gray-100 rounded-xl">
                      <p className="text-xs text-gray-400">No media added yet.</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
            <div className="px-6 py-4 bg-gray-50 border-t border-gray-100 flex items-center justify-end space-x-3">
              <button 
                onClick={() => setIsModalOpen(false)}
                disabled={isUploading}
                className="px-4 py-2 text-gray-600 font-semibold hover:bg-gray-100 rounded-xl transition-colors shrink-0"
              >
                Cancel
              </button>
              <button 
                onClick={saveAlbum}
                disabled={isUploading}
                className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-md transition-all active:scale-[0.98] disabled:opacity-50"
              >
                {currentAlbum?.id ? "Update Album" : "Create Album"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { 
  Users, 
  Search, 
  Trash2, 
  User, 
  Calendar, 
  Mail, 
  Phone,
  MapPin,
  ChevronLeft,
  ChevronRight,
  Loader2,
  Filter
} from "lucide-react";
import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import { 
  getMemberships, 
  deleteDashboardItem, 
  MembershipSubmission 
} from "@/lib/api/dashboard";
import { toast } from "react-hot-toast";

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

const ITEMS_PER_PAGE = 8;

export default function MembershipsPage() {
  const [searchTerm, setSearchTerm] = useState("");
  const [memberships, setMemberships] = useState<MembershipSubmission[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    fetchMemberships();
  }, []);

  const fetchMemberships = async () => {
    try {
      setLoading(true);
      const data = await getMemberships();
      setMemberships(data);
    } catch (error) {
      toast.error("Failed to load memberships");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (confirm("Are you sure you want to delete this submission?")) {
      try {
        await deleteDashboardItem("membership_applications", id);
        setMemberships(memberships.filter(m => m.id !== id));
        toast.success("Submission deleted");
      } catch (error) {
        toast.error("Failed to delete submission");
      }
    }
  };

  const formatDate = (timestamp: any) => {
    if (!timestamp) return "N/A";
    const date = timestamp.toDate();
    return date.toLocaleDateString("en-IN", {
      day: "numeric",
      month: "short",
      year: "numeric"
    });
  };

  const filteredMemberships = memberships.filter(m => {
    const searchTermLower = searchTerm.toLowerCase();
    const searchMatch = (m.fullName?.toLowerCase() || "").includes(searchTermLower) || 
                       (m.email?.toLowerCase() || "").includes(searchTermLower) ||
                       (m.phone?.toLowerCase() || "").includes(searchTermLower) ||
                       (m.occupation?.toLowerCase() || "").includes(searchTermLower);

    const statusMatch = statusFilter === "all" || m.status === statusFilter;

    return searchMatch && statusMatch;
  });

  const totalPages = Math.ceil(filteredMemberships.length / ITEMS_PER_PAGE);
  const paginatedMemberships = filteredMemberships.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Membership Management</h1>
          <p className="text-gray-500 text-sm mt-1">Review and manage membership applications from the website.</p>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="relative w-full sm:w-96">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-4 w-4 text-gray-400" />
          </div>
          <input
            type="text"
            className="block w-full pl-10 pr-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
            placeholder="Search by name, email or phone..."
            value={searchTerm}
            onChange={(e) => {
              setSearchTerm(e.target.value);
              setCurrentPage(1);
            }}
          />
        </div>
        <div className="flex items-center space-x-3">
          <select 
            value={statusFilter}
            onChange={(e) => {
              setStatusFilter(e.target.value);
              setCurrentPage(1);
            }}
            className="text-sm font-bold text-gray-600 border border-gray-200 px-3 py-2 rounded-lg bg-gray-50 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          >
            <option value="all">All Status</option>
            <option value="pending">Pending</option>
            <option value="approved">Approved</option>
          </select>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden min-h-[400px] flex flex-col font-sans">
        {loading ? (
          <div className="flex-1 flex justify-center items-center h-64">
            <Loader2 className="h-8 w-8 animate-spin text-indigo-600" />
          </div>
        ) : (
          <div className="flex-1 overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-100">
                  <th className="px-6 py-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Name</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Contact</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest">Type / Address</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest text-center">Submitted At</th>
                  <th className="px-6 py-4 text-[10px] font-bold text-gray-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {paginatedMemberships.map((member) => (
                  <tr key={member.id} className="hover:bg-gray-50/30 transition-colors group">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <div className="h-8 w-8 rounded-full bg-indigo-50 flex items-center justify-center text-indigo-600 mr-3">
                          <User size={16} />
                        </div>
                        <span className="text-sm font-bold text-gray-900">{member.fullName || "Unnamed"}</span>
                        {member.status && (
                          <span className={cn(
                            "ml-2 text-[8px] px-1.5 py-0.5 rounded-full font-bold uppercase tracking-tighter shadow-sm",
                            member.status === 'pending' ? "bg-amber-100 text-amber-600 border border-amber-200" : 
                            member.status === 'approved' ? "bg-green-100 text-green-600 border border-green-200" : "bg-gray-100 text-gray-600 border border-gray-200"
                          )}>
                            {member.status}
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex flex-col">
                        <span className="text-xs text-gray-600 flex items-center mb-1"><Mail size={12} className="mr-1.5 text-gray-400" /> {member.email || "No Email"}</span>
                        <span className="text-xs text-gray-600 flex items-center"><Phone size={12} className="mr-1.5 text-gray-400" /> {member.phone || "No Phone"}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-xs font-bold text-indigo-600 uppercase tracking-wider mb-1">{member.membershipType || "General"} • {member.occupation || "Member"}</span>
                        <span className="text-[10px] text-gray-400 line-clamp-1 flex items-center"><MapPin size={10} className="mr-1" /> {member.address || "N/A"}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-center">
                      <div className="flex items-center justify-center text-[10px] font-bold text-gray-500 uppercase tracking-wider">
                        <Calendar size={12} className="mr-1.5 opacity-50" />
                        {formatDate(member.createdAt)}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right">
                      <button 
                        onClick={() => handleDelete(member.id)}
                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors border border-transparent hover:border-red-100"
                        title="Delete"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))}

                {paginatedMemberships.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                      <div className="flex flex-col items-center">
                        <Users size={48} className="text-gray-200 mb-4" />
                        <p className="font-bold">No submissions found</p>
                        <p className="text-sm mt-1">Wait for public users to submit membership forms.</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        )}

        {totalPages > 1 && (
          <div className="px-6 py-4 bg-gray-50 border-t border-gray-100 flex items-center justify-between mt-auto">
            <p className="text-xs text-gray-500 font-medium tracking-wide">
              Showing <span className="font-bold text-gray-900">{(currentPage - 1) * ITEMS_PER_PAGE + 1}</span> to <span className="font-bold text-gray-900">{Math.min(currentPage * ITEMS_PER_PAGE, filteredMemberships.length)}</span> of <span className="font-bold text-gray-900">{filteredMemberships.length}</span> members
            </p>
            <div className="flex items-center space-x-2">
              <button 
                onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                disabled={currentPage === 1}
                className="p-2 border border-gray-200 rounded-lg bg-white text-gray-500 hover:bg-gray-50 disabled:opacity-50 transition-colors"
              >
                <ChevronLeft size={16} />
              </button>
              {Array.from({ length: totalPages }).map((_, i) => (
                <button
                  key={i}
                  onClick={() => setCurrentPage(i + 1)}
                  className={cn(
                    "w-8 h-8 flex items-center justify-center border rounded-lg text-xs font-bold transition-colors",
                    currentPage === i + 1 
                      ? "border-indigo-200 bg-indigo-50 text-indigo-600" 
                      : "border-gray-200 bg-white text-gray-600 hover:bg-gray-50"
                  )}
                >
                  {i + 1}
                </button>
              ))}
              <button 
                onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                disabled={currentPage === totalPages}
                className="p-2 border border-gray-200 rounded-lg bg-white text-gray-500 hover:bg-gray-50 disabled:opacity-50 transition-colors"
              >
                <ChevronRight size={16} />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { 
  Plus, 
  Trash2, 
  Edit2, 
  Pin, 
  Search, 
  FileText, 
  Calendar,
  X,
  Check,
  Loader2,
  Upload,
  Image as ImageIcon,
  ChevronLeft,
  ChevronRight
} from "lucide-react";
import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import { db } from "@/lib/firebase";
import { collection, getDocs, addDoc, updateDoc, deleteDoc, doc, query, orderBy } from "firebase/firestore";
import { uploadToCloudinary } from "@/lib/cloudinary";
import { toast } from "react-hot-toast";

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

interface Notice {
  id?: string;
  title: string;
  description?: string;
  category: string;
  date: string;
  pinned: boolean;
  hasPdf: boolean;
  pdfUrl?: string;
  thumbnailUrl?: string;
}

const ITEMS_PER_PAGE = 5;

export default function NoticesPage() {
  const [notices, setNotices] = useState<Notice[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentNotice, setCurrentNotice] = useState<Partial<Notice> | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [isImageUploading, setIsImageUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    fetchNotices();
  }, []);

  const fetchNotices = async () => {
    try {
      setLoading(true);
      const noticesCol = collection(db, "notices");
      // Use client-side sorting since we may not have a composite index set up yet
      const noticeSnapshot = await getDocs(noticesCol);
      const noticesList = noticeSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Notice[];

      // Sort: pinned first, then by date descending
      noticesList.sort((a, b) => {
        if (a.pinned === b.pinned) {
          return new Date(b.date).getTime() - new Date(a.date).getTime();
        }
        return a.pinned ? -1 : 1;
      });

      setNotices(noticesList);
    } catch (error) {
      console.error("Error fetching notices:", error);
      toast.error("Failed to load notices");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (confirm("Are you sure you want to delete this notice?")) {
      try {
        await deleteDoc(doc(db, "notices", id));
        setNotices(notices.filter(n => n.id !== id));
        toast.success("Notice deleted successfully");
      } catch (error) {
        console.error("Error deleting notice:", error);
        toast.error("Failed to delete notice");
      }
    }
  };

  const togglePin = async (notice: Notice) => {
    if (!notice.id) return;
    try {
      const noticeRef = doc(db, "notices", notice.id);
      await updateDoc(noticeRef, { pinned: !notice.pinned });
      setNotices(notices.map(n => n.id === notice.id ? { ...n, pinned: !n.pinned } : n));
      toast.success(notice.pinned ? "Notice unpinned" : "Notice pinned");
    } catch (error) {
      console.error("Error pinning notice:", error);
      toast.error("Failed to pin notice");
    }
  };

  const openModal = (notice: Notice | null = null) => {
    setCurrentNotice(notice || { 
      title: "", 
      description: "",
      category: "Announcement", 
      date: new Date().toISOString().split('T')[0], 
      pinned: false, 
      hasPdf: false,
      pdfUrl: "",
      thumbnailUrl: ""
    });
    setIsModalOpen(true);
  };

  const handleInputChange = (field: keyof Notice, value: any) => {
    if (currentNotice) {
      setCurrentNotice({ ...currentNotice, [field]: value });
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.type !== "application/pdf") {
      toast.error("Please upload a PDF file");
      return;
    }

    try {
      setIsUploading(true);
      const toastId = toast.loading("Uploading PDF...");

      const pdfUrl = await uploadToCloudinary(file);

      if (currentNotice) {
        setCurrentNotice({ ...currentNotice, hasPdf: true, pdfUrl });
      }

      toast.success("PDF uploaded successfully!", { id: toastId });
    } catch (error) {
      console.error("Upload error:", error);
      toast.error("Failed to upload PDF");
    } finally {
      setIsUploading(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith("image/")) {
      toast.error("Please upload an image file");
      return;
    }

    try {
      setIsImageUploading(true);
      const toastId = toast.loading("Uploading Thumbnail...");

      const imageUrl = await uploadToCloudinary(file);

      if (currentNotice) {
        setCurrentNotice({ ...currentNotice, thumbnailUrl: imageUrl });
      }

      toast.success("Thumbnail uploaded successfully!", { id: toastId });
    } catch (error) {
      console.error("Upload error:", error);
      toast.error("Failed to upload image");
    } finally {
      setIsImageUploading(false);
    }
  };

  const saveNotice = async () => {
    if (!currentNotice?.title || !currentNotice?.category) {
      toast.error("Title and Category are required");
      return;
    }

    try {
      if (currentNotice.id) {
        // Update
        const noticeRef = doc(db, "notices", currentNotice.id);
        const { id, ...updateData } = currentNotice as Notice;
        await updateDoc(noticeRef, updateData as any);
        toast.success("Notice updated");
      } else {
        // Create
        await addDoc(collection(db, "notices"), currentNotice);
        toast.success("Notice created");
      }
      setIsModalOpen(false);
      fetchNotices();
    } catch (error) {
      console.error("Error saving notice:", error);
      toast.error("Failed to save notice");
    }
  };

  const filteredNotices = notices.filter(n => n.title.toLowerCase().includes(searchTerm.toLowerCase()));
  const totalPages = Math.ceil(filteredNotices.length / ITEMS_PER_PAGE);
  const paginatedNotices = filteredNotices.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Notices & Announcements</h1>
          <p className="text-gray-500 text-sm mt-1">Create and manage public notices displayed on the website.</p>
        </div>
        <button 
          onClick={() => openModal()}
          className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition-all duration-200 shadow-sm"
        >
          <Plus className="h-4 w-4 mr-2" />
          Create Notice
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="relative w-full sm:w-96">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <Search className="h-4 w-4 text-gray-400" />
          </div>
          <input
            type="text"
            className="block w-full pl-10 pr-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
            placeholder="Search notices..."
            value={searchTerm}
            onChange={(e) => {
              setSearchTerm(e.target.value);
              setCurrentPage(1);
            }}
          />
        </div>
        <div className="flex items-center space-x-4">
          <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">Sort by:</span>
          <select className="text-sm border-none bg-transparent font-semibold text-gray-700 focus:ring-0 outline-none">
            <option>Recent First</option>
            <option>Oldest First</option>
          </select>
        </div>
      </div>

      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="application/pdf"
        onChange={handleFileUpload}
      />

      <input 
        type="file" 
        ref={imageInputRef} 
        className="hidden" 
        accept="image/*"
        onChange={handleImageUpload}
      />

      {loading ? (
        <div className="flex justify-center items-center h-64">
          <Loader2 className="w-8 h-8 animate-spin text-indigo-600" />
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {paginatedNotices.map((notice) => (
            <div key={notice.id} className={cn(
              "group bg-white rounded-2xl p-6 border transition-all duration-300 hover:shadow-lg relative overflow-hidden flex flex-col justify-between",
              notice.pinned ? "border-indigo-100 bg-indigo-50/10" : "border-gray-100"
            )}>
              {notice.pinned && (
                <div className="absolute top-0 right-0 w-16 h-16 pointer-events-none">
                  <div className="absolute transform rotate-45 bg-indigo-600 text-white text-[10px] font-bold py-1 px-8 right-[-24px] top-[12px] shadow-sm">
                    PINNED
                  </div>
                </div>
              )}

              <div>
                <div className="flex items-start justify-between mb-4">
                  <span className={cn(
                    "px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider",
                    notice.category === 'Meeting' ? "bg-amber-100 text-amber-700" : 
                    notice.category === 'Event' ? "bg-green-100 text-green-700" : "bg-blue-100 text-blue-700"
                  )}>
                    {notice.category}
                  </span>
                  <div className="flex items-center space-x-1 opacity-0 group-hover:opacity-100 transition-opacity">
