                  onChange={(e) => handleInputChange("description", e.target.value)}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-sm font-bold text-gray-700">Category</label>
                  <select 
                    className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={currentNotice?.category || "Announcement"}
                    onChange={(e) => handleInputChange("category", e.target.value)}
                  >
                    <option>Announcement</option>
                    <option>Meeting</option>
                    <option>Event</option>
                    <option>Maintenance</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-sm font-bold text-gray-700">Date</label>
                  <input 
                    type="date" 
                    className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={currentNotice?.date || ""}
                    onChange={(e) => handleInputChange("date", e.target.value)}
                  />
                </div>
              </div>

              <div className="pt-2 border-t border-gray-100 flex flex-col space-y-4">
                <label className="flex items-center space-x-2 cursor-pointer group w-fit">
                  <div className={cn(
                    "w-5 h-5 rounded border flex items-center justify-center transition-colors",
                    currentNotice?.pinned ? "bg-indigo-600 border-indigo-600" : "bg-white border-gray-300 group-hover:border-indigo-400"
                  )} onClick={() => handleInputChange("pinned", !currentNotice?.pinned)}>
                    {currentNotice?.pinned && <Check size={14} className="text-white" />}
                  </div>
                  <span className="text-sm font-bold text-gray-700">Pin to Top</span>
                </label>

                <div className="bg-gray-50 rounded-xl p-4 border border-gray-200 flex items-center justify-between">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg">
                      <ImageIcon size={20} />
                    </div>
                    <div className="min-w-0 flex-1">
                      <p className="text-sm font-bold text-gray-900 truncate">Notice Thumbnail</p>
                      <p className="text-xs text-gray-500">
                        {currentNotice?.thumbnailUrl ? "Thumbnail uploaded" : "No cover image"}
                      </p>
                    </div>
                  </div>
                  <div className="flex space-x-2">
                    {currentNotice?.thumbnailUrl && (
                      <div className="relative group/thumb">
                        <div className="w-10 h-10 rounded-lg border border-indigo-100 overflow-hidden shadow-sm">
                          <img src={currentNotice.thumbnailUrl} alt="Preview" className="w-full h-full object-cover" />
                        </div>
                        <button 
                          onClick={() => handleInputChange("thumbnailUrl", "")}
                          className="absolute -top-1.5 -right-1.5 p-0.5 bg-red-500 text-white rounded-full hover:bg-red-600 shadow-sm transition-all"
                        >
                          <X size={10} />
                        </button>
                      </div>
                    )}
                    <button 
                      onClick={() => imageInputRef.current?.click()}
                      disabled={isImageUploading || isUploading}
                      className="px-3 py-1.5 text-xs font-semibold text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 flex items-center disabled:opacity-50 h-fit self-center"
                    >
                      {isImageUploading ? <Loader2 size={14} className="animate-spin mr-1" /> : <Upload size={14} className="mr-1" />}
                      {currentNotice?.thumbnailUrl ? "Replace" : "Upload"}
                    </button>
                  </div>
                </div>

                <div className="bg-gray-50 rounded-xl p-4 border border-gray-200 flex items-center justify-between">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-red-100 text-red-600 rounded-lg">
                      <FileText size={20} />
                    </div>
                    <div>
                      <p className="text-sm font-bold text-gray-900">PDF Attachment</p>
                      <p className="text-xs text-gray-500">
                        {currentNotice?.hasPdf ? (currentNotice.pdfUrl ? "Document uploaded" : "Existing document attached") : "No document attached"}
                      </p>
                    </div>
                  </div>
                  <div className="flex space-x-2">
                    {currentNotice?.hasPdf && currentNotice.pdfUrl && (
                      <button 
                        onClick={() => handleInputChange("hasPdf", false)}
                        className="px-3 py-1.5 text-xs font-semibold text-red-600 bg-white border border-red-200 rounded-lg hover:bg-red-50"
                      >
                        Remove
                      </button>
                    )}
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      disabled={isUploading || isImageUploading}
                      className="px-3 py-1.5 text-xs font-semibold text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 flex items-center disabled:opacity-50"
                    >
                      {isUploading ? <Loader2 size={14} className="animate-spin mr-1" /> : <Upload size={14} className="mr-1" />}
                      {currentNotice?.hasPdf ? "Replace PDF" : "Upload PDF"}
                    </button>
                  </div>
                </div>
              </div>
            </div>
            <div className="px-6 py-4 bg-gray-50 border-t border-gray-100 flex items-center justify-end space-x-3">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-4 py-2 text-gray-600 font-semibold hover:bg-gray-100 rounded-xl transition-colors"
                disabled={isUploading}
              >
                Cancel
              </button>
              <button 
                onClick={saveNotice}
                disabled={isUploading}
                className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-md transition-all active:scale-[0.98] disabled:opacity-50"
              >
                {currentNotice?.id ? "Save Changes" : "Post Notice"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { 
  Users, 
  Calendar, 
  FileText, 
  MessageSquare, 
  TrendingUp, 
  Clock, 
  ChevronRight,
  ChevronLeft,
  ArrowUpRight,
  ArrowDownRight,
  Bell,
  X,
  Loader2
} from "lucide-react";
import { useAuth } from "@/context/AuthContext";
import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import { db } from "@/lib/firebase";
import { collection, getDocs, query, orderBy, limit } from "firebase/firestore";

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

interface StatCardProps {
  title: string;
  value: string | number;
  change: string;
  trend: "up" | "down" | "neutral";
  icon: React.ReactNode;
  color: string;
}

function StatCard({ title, value, change, trend, icon, color }: StatCardProps) {
  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-shadow">
      <div className="flex items-center justify-between mb-4">
        <div className={cn("p-3 rounded-xl", color)}>
          {icon}
        </div>
        {trend !== "neutral" && (
          <div className={cn(
            "flex items-center text-sm font-bold",
            trend === "up" ? "text-green-600" : "text-red-600"
          )}>
            {trend === "up" ? <ArrowUpRight size={16} /> : <ArrowDownRight size={16} />}
            <span className="ml-1">{change}</span>
          </div>
        )}
      </div>
      <div>
        <p className="text-sm font-bold text-gray-500 uppercase tracking-wider">{title}</p>
        <h3 className="text-2xl font-bold text-gray-900 mt-1">{value}</h3>
      </div>
    </div>
  );
}

interface Activity {
  id: string;
  type: 'booking' | 'notice' | 'document' | 'message' | 'system';
  user: string;
  action: string;
  createdAt: any;
  status?: 'success' | 'warning' | 'info' | 'error';
}

interface Booking {
  id: string;
  date: string;
  status: string;
  facility: string;
}

export default function DashboardOverview() {
  const { user } = useAuth();

  const [activities, setActivities] = useState<Activity[]>([]);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [stats, setStats] = useState({ bookings: 0, notices: 0, members: 0 });
  const [loading, setLoading] = useState(true);
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);

  // Calendar Navigation State
  const [currentMonth, setCurrentMonth] = useState(new Date().getMonth());
  const [currentYear, setCurrentYear] = useState(new Date().getFullYear());

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);

      // Fetch Recent Activities
      const activitiesSnap = await getDocs(query(collection(db, "activities"), orderBy("createdAt", "desc"), limit(6)));
      const acts = activitiesSnap.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Activity[];
      setActivities(acts);

      // Fetch Bookings for Calendar & Stats
      const bookingsSnap = await getDocs(collection(db, "bookings"));
      const bks = bookingsSnap.docs.map(doc => {
        const data = doc.data();
        let dateStr = "";
        if (data.date) {
            if (typeof data.date.toDate === 'function') {
                const theDate = data.date.toDate();
                dateStr = `${theDate.getFullYear()}-${String(theDate.getMonth() + 1).padStart(2, '0')}-${String(theDate.getDate()).padStart(2, '0')}`;
            } else {
                dateStr = String(data.date);
            }
        }
        return { 
          id: doc.id, 
          ...data,
          date: dateStr 
        };
      }) as Booking[];
      setBookings(bks);

      // Fetch Notices Stats
      const noticesSnap = await getDocs(collection(db, "notices"));

      // Fetch Committee Stats
      const committeeSnap = await getDocs(collection(db, "committee"));

      setStats({
        bookings: bks.length,
        notices: noticesSnap.size,
        members: committeeSnap.size
      });

    } catch (error) {
      console.error("Dashboard data error", error);
    } finally {
      setLoading(false);
    }
  };

  const getRelativeTime = (timestamp: any) => {
    if (!timestamp) return "Just now";
    const now = new Date();
    const past = timestamp.toDate();
    const diffInSeconds = Math.floor((now.getTime() - past.getTime()) / 1000);

    if (diffInSeconds < 60) return `${diffInSeconds}s ago`;
    if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
    if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
    return `${Math.floor(diffInSeconds / 86400)}d ago`;
  };

  const getCalendarDays = (month: number, year: number) => {
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const startPadding = firstDay.getDay(); // 0 is Sunday
    const daysInMonth = lastDay.getDate();

    const approvedBookings = bookings.filter(b => b.status === "approved");

    const days = [];
    // Padding from previous month
    for (let i = 0; i < startPadding; i++) {
      days.push({ day: null, booked: [] });
    }
    // Days of the current month
    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      // Extract simplified information for multiple bookings on the same day
      const dayBookings = approvedBookings
        .filter(b => {
          // Robust date comparison
          if (!b.date) return false;
          // Standardize date format for comparison (YYYY-MM-DD)
          let bDate = b.date;
          if (b.date.includes(',')) {
            // Handle "Mar 27, 2026" format from localized strings
            const parsedDate = new Date(b.date);
            bDate = `${parsedDate.getFullYear()}-${String(parsedDate.getMonth() + 1).padStart(2, '0')}-${String(parsedDate.getDate()).padStart(2, '0')}`;
          }
          return bDate === dateStr;
        })
        .map(b => ({
          id: b.id,
          facility: b.facility
        }));
      days.push({ day: d, booked: dayBookings });
    }

    return { year, month, days };
  };

  const calendarData = getCalendarDays(currentMonth, currentYear);
  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

  const handlePrevMonth = () => {
    if (currentMonth === 0) {
      setCurrentMonth(11);
      setCurrentYear(prev => prev - 1);
    } else {
      setCurrentMonth(prev => prev - 1);
    }
  };

  const handleNextMonth = () => {
    if (currentMonth === 11) {
      setCurrentMonth(0);
      setCurrentYear(prev => prev + 1);
    } else {
      setCurrentMonth(prev => prev + 1);
    }
  };

  return (
    <div className="space-y-8">
      {/* Welcome Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Welcome back, {user?.email?.split('@')[0] || "Admin"}!</h1>
          <p className="text-gray-500 text-sm mt-1">Here&apos;s what&apos;s happening with the Assam Association today.</p>
        </div>
        <div className="flex items-center space-x-2 bg-white px-4 py-2 rounded-xl shadow-sm border border-gray-100">
          <Clock className="text-indigo-600 h-4 w-4" />
          <span className="text-sm font-bold text-gray-600">{new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</span>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total Bookings" 
          value={loading ? "..." : stats.bookings} 
          change="Live" 
          trend="neutral" 
          icon={<Calendar className="text-white h-6 w-6" />}
          color="bg-indigo-600"
        />
        <StatCard 
          title="Active Notices" 
          value={loading ? "..." : stats.notices} 
          change="Live" 
          trend="neutral" 
          icon={<Bell className="text-white h-6 w-6" />}
          color="bg-amber-500"
        />
        <StatCard 
          title="Total Members" 
          value={loading ? "..." : stats.members} 
          change="Live" 
          trend="neutral" 
          icon={<Users className="text-white h-6 w-6" />}
          color="bg-blue-600"
        />
        <StatCard 
          title="System Health" 
          value="100%" 
          change="Online" 
          trend="neutral" 
          icon={<TrendingUp className="text-white h-6 w-6" />}
          color="bg-emerald-500"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Recent Activity */}
        <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[400px]">
          <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
            <h3 className="font-bold text-gray-900 flex items-center">
              <TrendingUp className="mr-2 text-indigo-600 h-5 w-5" />
              Recent System Activity
            </h3>
          </div>

          {loading ? (
             <div className="flex items-center justify-center p-12">
               <Loader2 className="h-8 w-8 animate-spin text-indigo-600" />
             </div>
          ) : activities.length === 0 ? (
            <div className="p-12 text-center text-gray-400">
              <p className="font-bold">No recent activities</p>
              <p className="text-sm">System actions will appear here automatically.</p>
            </div>
          ) : (
            <div className="divide-y divide-gray-50">
              {activities.map((activity) => (
                <div key={activity.id} className="px-6 py-4 flex items-center hover:bg-gray-50/50 transition-colors">
                  <div className={cn(
                    "h-10 w-10 rounded-xl flex items-center justify-center mr-4 shrink-0",
                    activity.type === 'booking' ? "bg-blue-50 text-blue-600" :
                    activity.type === 'notice' ? "bg-amber-50 text-amber-600" :
                    activity.type === 'document' ? "bg-purple-50 text-purple-600" : 
                    activity.type === 'system' ? "bg-indigo-50 text-indigo-600" : "bg-emerald-50 text-emerald-600"
                  )}>
                    {activity.type === 'booking' ? <Calendar size={18} /> :
                     activity.type === 'notice' ? <Bell size={18} /> :
                     activity.type === 'document' ? <FileText size={18} /> :
                     activity.type === 'system' ? <TrendingUp size={18} /> : <MessageSquare size={18} />}
                  </div>
                  <div className="flex-1">
                    <p className="text-sm text-gray-700">
                      <span className="font-bold text-gray-900">{activity.user}</span> {activity.action}
                    </p>
                    <p className="text-xs text-gray-400 mt-0.5">{getRelativeTime(activity.createdAt)}</p>
                  </div>
                  <ChevronRight className="text-gray-300 h-4 w-4 shrink-0 hidden sm:block" />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Actions / Summary */}
        <div className="space-y-6">
          <div className="bg-indigo-600 rounded-2xl p-6 text-white shadow-lg shadow-indigo-200 relative overflow-hidden group">
            <div className="absolute -right-6 -bottom-6 opacity-10 group-hover:scale-110 transition-transform duration-500">
              <Calendar size={160} />
            </div>
            <h3 className="text-lg font-bold mb-2">Hall Availability</h3>
            <p className="text-indigo-100 text-sm mb-4">You have {bookings.filter(b => b.status === "approved").length} approved bookings inside the database.</p>
            <button 
              onClick={() => setIsCalendarOpen(true)}
              className="bg-white text-indigo-600 px-4 py-2 rounded-xl text-sm font-bold active:scale-95 transition-all w-full text-center relative z-10"
            >
              Check Calendar
            </button>
          </div>

        </div>
      </div>

      {/* Calendar Modal */}
      {isCalendarOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between bg-white">
              <div className="flex items-center space-x-4">
                <button 
                  onClick={handlePrevMonth}
                  className="p-1.5 hover:bg-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 transition-colors border border-gray-100"
                >
                  <ChevronLeft size={18} />
                </button>
                <h2 className="text-xl font-bold flex items-center text-gray-900 min-w-[150px] justify-center">
                  {monthNames[calendarData.month]} {calendarData.year}
                </h2>
                <button 
                  onClick={handleNextMonth}
                  className="p-1.5 hover:bg-gray-100 rounded-lg text-gray-400 hover:text-indigo-600 transition-colors border border-gray-100"
                >
                  <ChevronRight size={18} />
                </button>
              </div>
              <button 
                onClick={() => setIsCalendarOpen(false)} 
                className="p-1 hover:bg-gray-100 rounded-full text-gray-500 transition-colors"
              >
                <X className="h-6 w-6" />
              </button>
            </div>

            <div className="p-6">
              <div className="grid grid-cols-7 gap-2 mb-2">
                {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
                  <div key={d} className="text-center text-xs font-bold text-gray-400 uppercase tracking-wider py-2">
                    {d}
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-7 gap-2">
                {calendarData.days.map((item, i) => (
                  <div 
                    key={i} 
                    className={cn(
                      "aspect-square rounded-xl flex flex-col items-start justify-start text-sm border transition-all p-1.5 overflow-hidden",
                      !item.day ? "border-transparent bg-transparent" :
                      item.booked.length > 0 
                        ? "bg-indigo-50 border-indigo-200 font-bold text-indigo-900 shadow-sm" 
                        : "bg-white border-gray-100 text-gray-600 hover:border-indigo-200"
                    )}
                  >
                    {item.day && (
                      <span className="mb-1 text-xs">{item.day}</span>
                    )}
                    {item.booked.length > 0 && (
                      <div className="flex flex-col gap-0.5 w-full overflow-y-auto no-scrollbar">
                        {item.booked.slice(0, 2).map((booking, idx) => (
                          <div 
                            key={idx} 
                            title={booking.facility}
                            className="text-[8px] leading-tight px-1 py-0.5 rounded bg-indigo-100 text-indigo-700 truncate w-full border border-indigo-200"
                          >
                            {booking.facility}
                          </div>
                        ))}
                        {item.booked.length > 2 && (
                          <div className="text-[7px] text-indigo-500 font-bold pl-1">
                            +{item.booked.length - 2} more
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                ))}
              </div>
              <div className="mt-6 flex items-center justify-center space-x-4 text-xs font-bold text-gray-500">
                <div className="flex items-center"><div className="w-3 h-3 rounded-full bg-indigo-500 mr-2"></div> Booked Facility</div>
                <div className="flex items-center"><div className="w-3 h-3 rounded-full border border-gray-200 mr-2"></div> Available</div>
              </div>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { 
  Plus, 
  Trash2, 
  Edit2, 
  Camera, 
  X,
  Loader2,
  Upload,
  ChevronLeft,
  ChevronRight,
  MinusCircle
} from "lucide-react";
import Image from "next/image";
import { uploadToCloudinary } from "@/lib/cloudinary";
import { toast } from "react-hot-toast";
import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import { db } from "@/lib/firebase";
import { collection, getDocs, addDoc, updateDoc, deleteDoc, doc, serverTimestamp } from "firebase/firestore";
import { logActivity } from "@/lib/activity";
import { useAuth } from "@/context/AuthContext";

function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export type FacilityType = "simple" | "accommodation" | "event";

export interface Room {
  id: string;
  name: string;
  description: string;
  price: number;
  inclusions: string;
  bookingPolicy: string;
  checkIn: string;
  checkOut: string;
  images?: string[];
}

export interface PricingSlot {
  id: string;
  duration: string;
  amount: number;
}

export interface Facility {
  id: string;
  name: string;
  description: string;
  image: string;
  gallery?: string[];
  type: FacilityType;

  // Accommodation
  rooms?: Room[];

  // Event
  pricing?: PricingSlot[];
  bookingPolicy?: string;
  remarks?: string;

  createdAt?: any;
}

const ITEMS_PER_PAGE = 5;

export default function ServicesPage() {
  const { user } = useAuth();
  const [facilities, setFacilities] = useState<Facility[]>([]);
  const [loading, setLoading] = useState(true);

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentFacility, setCurrentFacility] = useState<Partial<Facility> | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isUploadingGallery, setIsUploadingGallery] = useState(false);
  const [uploadingRoomId, setUploadingRoomId] = useState<string | null>(null);
  const galleryInputRef = useRef<HTMLInputElement>(null);
  const roomImageInputRef = useRef<HTMLInputElement>(null);
  const [currentRoomForUpload, setCurrentRoomForUpload] = useState<string | null>(null);

  useEffect(() => {
    fetchFacilities();
  }, []);

  const fetchFacilities = async () => {
    try {
      setLoading(true);
      const querySnapshot = await getDocs(collection(db, "facilities"));
      const docsList = querySnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Facility[];

      // Sort by creation or fallback to name
      docsList.sort((a, b) => {
        if (a.createdAt && b.createdAt) {
          return b.createdAt.toMillis() - a.createdAt.toMillis();
        }
        return a.name.localeCompare(b.name);
      });

      setFacilities(docsList);
    } catch (error) {
      console.error("Error fetching facilities:", error);
      toast.error("Failed to load facilities");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string, name: string) => {
    if (confirm("Are you sure you want to delete this facility entry?")) {
      try {
        await deleteDoc(doc(db, "facilities", id));
        setFacilities(facilities.filter(f => f.id !== id));

        await logActivity("system", user?.email?.split('@')[0] || "Admin", `deleted facility: ${name}`, "warning");
        toast.success("Entry removed");
      } catch (error) {
        console.error("Error deleting facility:", error);
        toast.error("Failed to delete entry");
      }
    }
  };

  const openModal = (facility: Facility | null = null) => {
    setCurrentFacility(facility || { 
      name: "", 
      description: "", 
      image: "", 
      gallery: [],
      type: "simple",
      rooms: [],
      pricing: [],
      bookingPolicy: "",
      remarks: ""
    });
    setIsModalOpen(true);
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      setIsUploading(true);
      const toastId = toast.loading("Uploading and optimizing facility image...");

      const imageUrl = await uploadToCloudinary(file);

      if (currentFacility) {
        setCurrentFacility({ ...currentFacility, image: imageUrl });
      }

      toast.success("Image uploaded successfully!", { id: toastId });
    } catch (error) {
      console.error(error);
      toast.error(error instanceof Error ? error.message : "Upload failed");
    } finally {
      setIsUploading(false);
    }
  };

  const handleGalleryUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    try {
      setIsUploadingGallery(true);
      const toastId = toast.loading(`Uploading ${files.length} images...`);

      const uploadPromises = files.map(file => uploadToCloudinary(file));
      const fileUrls = await Promise.all(uploadPromises);

      setCurrentFacility(prev => ({
        ...prev,
        gallery: [...(prev?.gallery || []), ...fileUrls]
      }));

      toast.success("Gallery images uploaded successfully!", { id: toastId });
    } catch (error) {
      console.error("Gallery upload error:", error);
      toast.error(error instanceof Error ? error.message : "Upload failed");
    } finally {
      setIsUploadingGallery(false);
      if (galleryInputRef.current) galleryInputRef.current.value = "";
    }
  };

  const removeGalleryImage = (indexToRemove: number) => {
    setCurrentFacility(prev => ({
      ...prev,
      gallery: (prev?.gallery || []).filter((_, index) => index !== indexToRemove)
    }));
  };

  const handleRoomImageUpload = async (roomId: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    try {
      setUploadingRoomId(roomId);
      const toastId = toast.loading(`Uploading ${files.length} images...`);

      const uploadPromises = files.map(file => uploadToCloudinary(file));
      const fileUrls = await Promise.all(uploadPromises);

      setCurrentFacility(prev => ({
        ...prev,
        rooms: (prev?.rooms || []).map(r => r.id === roomId ? { ...r, images: [...(r.images || []), ...fileUrls] } : r)
      }));

      toast.success("Room images uploaded successfully!", { id: toastId });
    } catch (error) {
      console.error("Room image upload error:", error);
      toast.error(error instanceof Error ? error.message : "Upload failed");
    } finally {
      setUploadingRoomId(null);
      setCurrentRoomForUpload(null);
      if (roomImageInputRef.current) roomImageInputRef.current.value = "";
    }
  };

  const removeRoomImage = (roomId: string, indexToRemove: number) => {
    setCurrentFacility(prev => ({
      ...prev,
      rooms: (prev?.rooms || []).map(r => 
        r.id === roomId 
          ? { ...r, images: (r.images || []).filter((_, index) => index !== indexToRemove) } 
          : r
      )
    }));
  };

  const saveFacility = async () => {
    if (!currentFacility?.name || !currentFacility?.image) {
      toast.error("Name and Image are required");
      return;
    }

    try {
      const adminName = user?.email?.split('@')[0] || "Admin";

      // Clean up irrelevant fields based on type
      const dataToSave = { ...currentFacility };
      if (dataToSave.type === 'simple') {
        delete dataToSave.rooms;
        delete dataToSave.pricing;
        delete dataToSave.bookingPolicy;
        delete dataToSave.remarks;
      } else if (dataToSave.type === 'accommodation') {
        delete dataToSave.pricing;
        delete dataToSave.remarks;
        // Keep bookingPolicy possibly, or put it per room? Requirements say per room for accommodation, but keeping global doesn't hurt.
        // Actually, requirements mention bookingPolicy inside room for accommodation.
        delete dataToSave.bookingPolicy; 
      } else if (dataToSave.type === 'event') {
        delete dataToSave.rooms;
      }

      if (currentFacility.id) {
        const docRef = doc(db, "facilities", currentFacility.id);
        const { id, ...updateData } = dataToSave;
        await updateDoc(docRef, updateData as any);

        await logActivity("system", adminName, `updated facility: ${currentFacility.name}`, "info");
        toast.success("Facility updated");
      } else {
        const newDoc = {
          ...dataToSave,
          createdAt: serverTimestamp()
        };
        await addDoc(collection(db, "facilities"), newDoc);

        await logActivity("system", adminName, `added new facility: ${currentFacility.name}`, "success");
        toast.success("New facility added");
      }
      setIsModalOpen(false);
      fetchFacilities();
    } catch (error) {
      console.error("Error saving facility:", error);
      toast.error("Failed to save facility");
    }
  };

  // Dynamic Array Handlers
  const addRoom = () => {
    setCurrentFacility(prev => ({
      ...prev,
      rooms: [...(prev?.rooms || []), {
        id: Math.random().toString(36).substr(2, 9),
        name: "",
        description: "",
        price: 0,
        inclusions: "",
        bookingPolicy: "",
        checkIn: "",
        checkOut: "",
        images: []
      }]
    }));
  };

  const removeRoom = (id: string) => {
    setCurrentFacility(prev => ({
      ...prev,
      rooms: (prev?.rooms || []).filter(r => r.id !== id)
    }));
  };

  const updateRoom = (id: string, field: keyof Room, value: any) => {
    setCurrentFacility(prev => ({
      ...prev,
      rooms: (prev?.rooms || []).map(r => r.id === id ? { ...r, [field]: value } : r)
    }));
  };

  const addPricingSlot = () => {
    setCurrentFacility(prev => ({
      ...prev,
      pricing: [...(prev?.pricing || []), {
        id: Math.random().toString(36).substr(2, 9),
        duration: "",
        amount: 0
      }]
    }));
  };

  const removePricingSlot = (id: string) => {
    setCurrentFacility(prev => ({
      ...prev,
      pricing: (prev?.pricing || []).filter(p => p.id !== id)
    }));
  };

  const updatePricingSlot = (id: string, field: keyof PricingSlot, value: any) => {
    setCurrentFacility(prev => ({
      ...prev,
      pricing: (prev?.pricing || []).map(p => p.id === id ? { ...p, [field]: value } : p)
    }));
  };

  // Pagination Logic
  const totalPages = Math.ceil((facilities.length + 1) / ITEMS_PER_PAGE);
  const paginatedItems = () => {
    const blendedArray = [...facilities, "ADD_CARD" as const];
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return blendedArray.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  };

  const getDisplayPrice = (facility: Facility) => {
    if (facility.type === "accommodation" && facility.rooms && facility.rooms.length > 0) {
      const minPrice = Math.min(...facility.rooms.map(r => Number(r.price) || 0));
      return minPrice > 0 ? `Starts from ₹${minPrice}` : "Contact for pricing";
    }
    if (facility.type === "event" && facility.pricing && facility.pricing.length > 0) {
      const minPrice = Math.min(...facility.pricing.map(p => Number(p.amount) || 0));
      return minPrice > 0 ? `Starts from ₹${minPrice}` : "Contact for pricing";
    }
    return "";
  };

  const getFacilityTypeLabel = (type: string) => {
    switch(type) {
      case 'simple': return 'Facility';
      case 'accommodation': return 'Accommodation';
      case 'event': return 'Event Space';
      default: return 'Facility';
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Services & Facilities</h1>
          <p className="text-gray-500 text-sm mt-1">Manage information about auditorium, guest house, and other services.</p>
        </div>
        <button 
          onClick={() => openModal()}
          className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition-all duration-200 shadow-sm"
        >
          <Plus className="h-4 w-4 mr-2" />
          Add New Facility
        </button>
      </div>

      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*" 
        onChange={handleImageUpload}
      />
      <input 
        type="file" 
        ref={galleryInputRef} 
        className="hidden" 
        accept="image/*" 
        multiple
        onChange={handleGalleryUpload}
      />
      <input 
        type="file" 
        ref={roomImageInputRef} 
        className="hidden" 
        accept="image/*" 
        multiple
        onChange={(e) => {
          if (currentRoomForUpload) {
            handleRoomImageUpload(currentRoomForUpload, e);
          }
        }}
      />

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <Loader2 className="h-10 w-10 animate-spin text-indigo-600" />
        </div>
      ) : (
        <>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 min-h-[400px]">
            {paginatedItems().map((item, index) => {
              if (item === "ADD_CARD") {
                return (
                  <button 
                    key="add-card"
                    onClick={() => openModal()}
                    className="flex flex-col items-center justify-center p-8 border-2 border-dashed border-gray-200 rounded-2xl bg-gray-50 hover:bg-gray-100 hover:border-indigo-300 transition-all duration-300 group min-h-[300px]"
                  >
                    <div className="p-4 bg-white rounded-full shadow-sm group-hover:scale-110 transition-transform duration-300 mb-4 text-indigo-600">
                      <Plus size={32} />
                    </div>
                    <span className="text-sm font-bold text-gray-500 group-hover:text-indigo-600">Add Service / Facility</span>
                  </button>
                );
              }

              const facility = item as Facility;
              const displayPrice = getDisplayPrice(facility);

              return (
                <div key={facility.id || index} className="group bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-xl transition-all duration-300 flex flex-col">
                  <div className="relative h-48 w-full bg-gray-100">
                    <Image 
                      src={facility.image} 
                      alt={facility.name || "Facility Image"} 
                      fill 
                      sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
                      className="object-cover group-hover:scale-105 transition-transform duration-500" 
                    />
                    <div className="absolute top-4 left-4">
                      <span className="px-3 py-1 bg-white/90 backdrop-blur-md text-[10px] font-bold text-indigo-600 uppercase tracking-widest rounded-full shadow-sm">
                        {getFacilityTypeLabel(facility.type)}
                      </span>
                    </div>
                  </div>

                  <div className="p-6 flex-1 flex flex-col">
                    <h3 className="text-lg font-bold text-gray-900 mb-2 leading-tight">{facility.name}</h3>
                    <p className="text-sm text-gray-500 mb-4 line-clamp-3">{facility.description}</p>

                    <div className="mt-auto flex items-center justify-between pt-4 border-t border-gray-50">
                      <div className="text-sm font-bold text-indigo-600">
                        {displayPrice}
                      </div>
                      <div className="flex items-center space-x-2">
                        <button 
                          onClick={() => openModal(facility)}
                          className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-all"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button 
                          onClick={() => handleDelete(facility.id, facility.name)}
                          className="p-2 text-gray-400 hover:text-red-600 hover:bg-gray-50 rounded-lg transition-all"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {totalPages > 1 && (
            <div className="flex items-center justify-between bg-white px-6 py-4 rounded-xl border border-gray-100 shadow-sm">
              <p className="text-sm text-gray-500 font-medium">
                Showing <span className="font-bold text-gray-900">{(currentPage - 1) * ITEMS_PER_PAGE + 1}</span> to <span className="font-bold text-gray-900">{Math.min(currentPage * ITEMS_PER_PAGE, facilities.length + 1)}</span> of <span className="font-bold text-gray-900">{facilities.length + 1}</span> items
              </p>
              <div className="flex items-center space-x-2">
                <button 
                  onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                  disabled={currentPage === 1}
                  className="p-2 border border-gray-200 rounded-lg bg-white text-gray-500 hover:bg-gray-50 disabled:opacity-50 transition-colors"
                >
                  <ChevronLeft size={16} />
                </button>
                {Array.from({ length: totalPages }).map((_, i) => (
                  <button
                    key={i}
                    onClick={() => setCurrentPage(i + 1)}
                    className={cn(
                      "w-8 h-8 flex items-center justify-center border rounded-lg text-sm font-bold transition-colors",
                      currentPage === i + 1 
                        ? "border-indigo-200 bg-indigo-50 text-indigo-600" 
                        : "border-gray-200 bg-white text-gray-600 hover:bg-gray-50"
                    )}
                  >
                    {i + 1}
                  </button>
                ))}
                <button 
                  onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                  disabled={currentPage === totalPages}
                  className="p-2 border border-gray-200 rounded-lg bg-white text-gray-500 hover:bg-gray-50 disabled:opacity-50 transition-colors"
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            </div>
          )}
        </>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-3xl rounded-2xl shadow-2xl overflow-y-auto max-h-[90vh] my-8 relative">
            <div className="sticky top-0 z-10 px-6 py-4 border-b border-gray-100 flex items-center justify-between bg-indigo-600 text-white">
              <h2 className="text-xl font-bold">{currentFacility?.id ? "Edit Facility" : "Add Facility"}</h2>
              <button 
                onClick={() => setIsModalOpen(false)} 
                disabled={isUploading}
                className="p-1 hover:bg-white/20 rounded-full transition-colors"
              >
                <X className="h-6 w-6" />
              </button>
            </div>
            <div className="p-6 space-y-6">
              <div 
                className={cn(
                  "relative h-48 rounded-xl bg-gray-100 border-2 border-dashed border-gray-200 flex flex-col items-center justify-center overflow-hidden cursor-pointer hover:border-indigo-300 transition-all",
                  isUploading && "opacity-50 pointer-events-none"
                )}
                onClick={() => fileInputRef.current?.click()}
              >
                {isUploading ? (
                  <Loader2 size={32} className="animate-spin text-indigo-600" />
                ) : currentFacility?.image ? (
                  <>
                    <Image src={currentFacility.image} fill sizes="(max-width: 768px) 100vw, 500px" alt={currentFacility.name || "Facility"} className="object-cover" />
                    <div className="absolute inset-0 bg-black/20 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
                      <Camera size={32} className="text-white" />
                    </div>
                  </>
                ) : (
                  <>
                    <Upload size={32} className="text-gray-400 mb-2" />
                    <p className="text-sm font-bold text-gray-400">Upload Cover Image</p>
                  </>
                )}
              </div>

              {/* Facility Gallery */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <label className="text-sm font-bold text-gray-700">Facility Gallery</label>
                  <button
                    type="button"
                    onClick={() => galleryInputRef.current?.click()}
                    disabled={isUploadingGallery}
                    className="inline-flex items-center px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-lg text-sm font-bold hover:bg-indigo-100 transition-colors disabled:opacity-50"
                  >
                    {isUploadingGallery ? <Loader2 className="w-4 h-4 mr-1 animate-spin" /> : <Plus className="w-4 h-4 mr-1" />}
                    Add Images
                  </button>
                </div>
                {currentFacility?.gallery && currentFacility.gallery.length > 0 ? (
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    {currentFacility.gallery.map((img, idx) => (
                      <div key={idx} className="relative group aspect-video rounded-lg overflow-hidden border border-gray-200 bg-gray-50">
                        <Image src={img} fill alt={`Gallery ${idx}`} className="object-cover" />
                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                          <button
                            type="button"
                            onClick={() => removeGalleryImage(idx)}
                            className="p-1.5 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-6 border-2 border-dashed border-gray-200 rounded-xl bg-gray-50">
                    <p className="text-sm text-gray-500">No gallery images added yet.</p>
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-sm font-bold text-gray-700">Facility Name</label>
                  <input 
                    type="text" 
                    className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    placeholder="e.g. Guest House"
                    value={currentFacility?.name || ""}
                    onChange={(e) => setCurrentFacility({ ...currentFacility, name: e.target.value })}
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-sm font-bold text-gray-700">Facility Type</label>
                  <select 
                    className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={currentFacility?.type || "simple"}
                    onChange={(e) => {
                      const newType = e.target.value as FacilityType;
                      setCurrentFacility({ 
                        ...currentFacility, 
                        type: newType,
                        rooms: newType === 'accommodation' ? currentFacility?.rooms || [] : [],
                        pricing: newType === 'event' ? currentFacility?.pricing || [] : []
                      });
                    }}
                  >
                    <option value="simple">Simple Facility (e.g. Library)</option>
                    <option value="accommodation">Accommodation (e.g. Guest House)</option>
                    <option value="event">Event Space (e.g. Auditorium)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-sm font-bold text-gray-700">General Description</label>
                <textarea 
                  className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none h-24"
                  placeholder="Describe the facility generally..."
                  value={currentFacility?.description || ""}
                  onChange={(e) => setCurrentFacility({ ...currentFacility, description: e.target.value })}
                />
              </div>

              {/* Dynamic Sections Based on Type */}
              {currentFacility?.type === 'accommodation' && (
                <div className="mt-8 border-t border-gray-200 pt-6">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-bold text-gray-900">Rooms Configuration</h3>
                    <button 
                      onClick={addRoom}
                      className="inline-flex items-center px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-lg text-sm font-bold hover:bg-indigo-100 transition-colors"
                    >
                      <Plus className="h-4 w-4 mr-1" />
                      Add Room
                    </button>
                  </div>

                  <div className="space-y-4">
                    {currentFacility.rooms?.map((room, index) => (
                      <div key={room.id} className="p-4 border border-gray-200 rounded-xl bg-gray-50 relative">
                        <button 
                          onClick={() => removeRoom(room.id)}
                          className="absolute top-4 right-4 text-gray-400 hover:text-red-500 transition-colors"
                        >
                          <MinusCircle className="h-5 w-5" />
                        </button>
                        <h4 className="font-bold text-gray-700 mb-3 text-sm">Room {index + 1}</h4>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div className="space-y-1">
                            <label className="text-xs font-semibold text-gray-600">Room Name</label>
                            <input 
                              type="text" 
                              className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                              placeholder="e.g. Double Bed AC Room"
                              value={room.name || ""}
                              onChange={(e) => updateRoom(room.id, 'name', e.target.value)}
                            />
                          </div>
                          <div className="space-y-1">
                            <label className="text-xs font-semibold text-gray-600">Price (₹)</label>
                            <input 
                              type="number" 
                              className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                              placeholder="0"
                              value={room.price || ""}
                              onChange={(e) => updateRoom(room.id, 'price', Number(e.target.value))}
                            />
                          </div>
                          <div className="space-y-1 md:col-span-2">
                            <label className="text-xs font-semibold text-gray-600">Description</label>
                            <input 
                              type="text" 
                              className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                              placeholder="Brief room description"
                              value={room.description || ""}
                              onChange={(e) => updateRoom(room.id, 'description', e.target.value)}
                            />
                          </div>
                          <div className="space-y-1 md:col-span-2">
                            <label className="text-xs font-semibold text-gray-600">Inclusions</label>
                            <input 
                              type="text" 
                              className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                              placeholder="e.g. Free Breakfast, WiFi"
                              value={room.inclusions || ""}
                              onChange={(e) => updateRoom(room.id, 'inclusions', e.target.value)}
                            />
                          </div>
                          <div className="space-y-1">
                            <label className="text-xs font-semibold text-gray-600">Check-in Time</label>
                            <input 
                              type="text" 
                              className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                              placeholder="e.g. 12:00 PM"
                              value={room.checkIn || ""}
                              onChange={(e) => updateRoom(room.id, 'checkIn', e.target.value)}
                            />
                          </div>
                          <div className="space-y-1">
                            <label className="text-xs font-semibold text-gray-600">Check-out Time</label>
                            <input 
                              type="text" 
                              className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                              placeholder="e.g. 11:00 AM"
                              value={room.checkOut || ""}
                              onChange={(e) => updateRoom(room.id, 'checkOut', e.target.value)}
                            />
                          </div>
                          <div className="space-y-1 md:col-span-2">
                            <label className="text-xs font-semibold text-gray-600">Booking Policy (Optional)</label>
                            <textarea 
                              className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none h-16"
                              placeholder="Any specific policy for this room..."
                              value={room.bookingPolicy || ""}
                              onChange={(e) => updateRoom(room.id, 'bookingPolicy', e.target.value)}
                            />
                          </div>

                          {/* Room Images */}
                          <div className="space-y-2 md:col-span-2 mt-2 pt-4 border-t border-gray-100">
                            <div className="flex items-center justify-between">
                              <label className="text-xs font-semibold text-gray-600">Room Images</label>
                              <button
                                type="button"
                                onClick={() => {
                                  setCurrentRoomForUpload(room.id);
                                  roomImageInputRef.current?.click();
                                }}
                                disabled={uploadingRoomId === room.id}
                                className="inline-flex items-center px-2 py-1 bg-gray-100 text-gray-600 rounded-md text-xs font-bold hover:bg-gray-200 transition-colors disabled:opacity-50"
                              >
                                {uploadingRoomId === room.id ? <Loader2 className="w-3 h-3 mr-1 animate-spin" /> : <Plus className="w-3 h-3 mr-1" />}
                                Upload Room Images
                              </button>
                            </div>
                            {room.images && room.images.length > 0 ? (
                              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                                {room.images.map((img, idx) => (
                                  <div key={idx} className="relative group aspect-video rounded-md overflow-hidden border border-gray-200 bg-gray-50">
                                    <Image src={img} fill alt={`Room ${room.name} image ${idx}`} className="object-cover" />
                                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                      <button
                                        type="button"
                                        onClick={() => removeRoomImage(room.id, idx)}
                                        className="p-1 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
                                      >
                                        <Trash2 className="w-3 h-3" />
                                      </button>
                                    </div>
                                  </div>
                                ))}
                              </div>
                            ) : (
                              <div className="text-center py-4 text-xs text-gray-400 bg-white border border-dashed border-gray-200 rounded-md">
                                No images uploaded for this room.
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                    {(!currentFacility.rooms || currentFacility.rooms.length === 0) && (
                      <div className="text-center py-8 text-gray-400 text-sm">
                        No rooms added yet. Click "Add Room" to get started.
                      </div>
                    )}
                  </div>
                </div>
              )}

              {currentFacility?.type === 'event' && (
                <div className="mt-8 border-t border-gray-200 pt-6">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-bold text-gray-900">Pricing Slots</h3>
                    <button 
                      onClick={addPricingSlot}
                      className="inline-flex items-center px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-lg text-sm font-bold hover:bg-indigo-100 transition-colors"
                    >
                      <Plus className="h-4 w-4 mr-1" />
                      Add Slot
                    </button>
                  </div>

                  <div className="space-y-4 mb-6">
                    {currentFacility.pricing?.map((slot, index) => (
                      <div key={slot.id} className="flex gap-4 items-start p-3 border border-gray-200 rounded-xl bg-gray-50">
                        <div className="flex-1 space-y-1">
                          <label className="text-xs font-semibold text-gray-600">Duration / Slot Type</label>
                          <input 
                            type="text" 
                            className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                            placeholder="e.g. Day Time (09 AM to 04 PM)"
                            value={slot.duration || ""}
                            onChange={(e) => updatePricingSlot(slot.id, 'duration', e.target.value)}
                          />
                        </div>
                        <div className="w-1/3 space-y-1">
                          <label className="text-xs font-semibold text-gray-600">Amount (₹)</label>
                          <input 
                            type="number" 
                            className="w-full px-3 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                            placeholder="0"
                            value={slot.amount || ""}
                            onChange={(e) => updatePricingSlot(slot.id, 'amount', Number(e.target.value))}
                          />
                        </div>
                        <button 
                          onClick={() => removePricingSlot(slot.id)}
                          className="mt-6 text-gray-400 hover:text-red-500 transition-colors"
                        >
                          <MinusCircle className="h-5 w-5" />
                        </button>
                      </div>
                    ))}
                    {(!currentFacility.pricing || currentFacility.pricing.length === 0) && (
                      <div className="text-center py-6 text-gray-400 text-sm">
                        No pricing slots added yet.
                      </div>
                    )}
                  </div>

                  <div className="space-y-4">
                    <div className="space-y-1">
                      <label className="text-sm font-bold text-gray-700">Booking Policy</label>
                      <textarea 
                        className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none h-20"
                        placeholder="General booking policy for this space..."
                        value={currentFacility?.bookingPolicy || ""}
                        onChange={(e) => setCurrentFacility({ ...currentFacility, bookingPolicy: e.target.value })}
                      />
                    </div>
                    <div className="space-y-1">
                      <label className="text-sm font-bold text-gray-700">Remarks / Extra Charges</label>
                      <textarea 
                        className="w-full px-4 py-2 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none h-20"
                        placeholder="e.g. Cleaning charges ₹1000 extra..."
                        value={currentFacility?.remarks || ""}
                        onChange={(e) => setCurrentFacility({ ...currentFacility, remarks: e.target.value })}
                      />
                    </div>
                  </div>
                </div>
              )}

            </div>
            <div className="sticky bottom-0 z-10 px-6 py-4 bg-gray-50 border-t border-gray-100 flex items-center justify-end space-x-3">
              <button 
                onClick={() => setIsModalOpen(false)}
                disabled={isUploading}
                className="px-4 py-2 text-gray-600 font-semibold hover:bg-gray-100 rounded-xl transition-colors shrink-0"
              >
                Cancel
              </button>
              <button 
                onClick={saveFacility}
                disabled={isUploading}
                className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-md transition-all active:scale-[0.98] disabled:opacity-50"
              >
                {currentFacility?.id ? "Update Facility" : "Save Facility"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { db } from "./firebase";
import { collection, addDoc, serverTimestamp } from "firebase/firestore";

export type ActivityType = "booking" | "notice" | "document" | "message" | "system";
export type ActivityStatus = "success" | "warning" | "info" | "error";

export interface ActivityLog {
  type: ActivityType;
  user: string;
  action: string;
  status: ActivityStatus;
  createdAt: any;
}

export const logActivity = async (
  type: ActivityType,
  user: string,
  action: string,
  status: ActivityStatus = "info"
) => {
  try {
    await addDoc(collection(db, "activities"), {
      type,
      user,
      action,
      status,
      createdAt: serverTimestamp(),
    });
  } catch (error) {
    console.error("Failed to log activity:", error);
  }
};
